--
-- Name: v_device_current_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_device_current_status AS
 SELECT d.device_id,
    d.device_code,
    d.device_name,
    hp.x AS last_x,
    hp.y AS last_y,
    hp.yaw AS last_yaw,
    hb.battery_percent,
    hs.robot_mode,
    hs.robot_activity,
    hs.recorded_at AS status_updated_at
   FROM (((public.m_device d
     LEFT JOIN LATERAL ( SELECT hp2.x,
            hp2.y,
            hp2.yaw,
            hp2.recorded_at
           FROM public.h_position hp2
          WHERE (hp2.device_id = d.device_id)
          ORDER BY hp2.recorded_at DESC
         LIMIT 1) hp ON (true))
     LEFT JOIN LATERAL ( SELECT hb2.battery_percent,
            hb2.recorded_at
           FROM public.h_battery hb2
          WHERE (hb2.device_id = d.device_id)
          ORDER BY hb2.recorded_at DESC
         LIMIT 1) hb ON (true))
     LEFT JOIN LATERAL ( SELECT hs2.robot_mode,
            hs2.robot_activity,
            hs2.recorded_at
           FROM public.h_state hs2
          WHERE (hs2.device_id = d.device_id)
          ORDER BY hs2.recorded_at DESC
         LIMIT 1) hs ON (true));


ALTER VIEW public.v_device_current_status OWNER TO postgres;

